class NewsfeedApi extends BaseApiWithErrors {
  feeds = [];
  commentsByFeedId = {};
  isNewFeedModalOpen = false;
  /**
   * Opens the new feed modal
   */
  openNewFeedModal() {
    this.isNewFeedModalOpen = true;
  }
  /**
   * Closes the new feed modal
   */
  closeNewFeedModal() {
    this.isNewFeedModalOpen = false;
  }
  /**
   * Lists newsfeed items for a course
   */
  async list(courseId) {
    await this.execute({
      requestFn: () => classroomio.course[":courseId"].newsfeed.$get({ param: { courseId }, query: {} }),
      logContext: "listing newsfeed",
      onSuccess: (response) => {
        if (response.data) {
          this.feeds = Array.isArray(response.data) ? response.data : response.data.items || [];
          for (const feed of this.feeds) {
            this.initComments(feed.id, 0);
          }
        }
      },
      onError: (result) => {
        if (typeof result === "string") {
          snackbar.error("Failed to list newsfeed");
        }
      }
    });
  }
  /**
   * Gets a newsfeed item by ID
   */
  async get(courseId, feedId) {
    await this.execute({
      requestFn: () => classroomio.course[":courseId"].newsfeed[":feedId"].$get({ param: { courseId, feedId } }),
      logContext: "fetching newsfeed item",
      onError: (result) => {
        if (typeof result === "string") {
          snackbar.error("Failed to fetch newsfeed item");
        }
      }
    });
  }
  /**
   * Creates a new newsfeed item
   */
  async create(courseId, fields) {
    const result = ZNewsfeedCreate.safeParse({
      ...fields,
      content: getTextFromHTML(fields.content),
      courseId
    });
    if (!result.success) {
      this.errors = mapZodErrorsToTranslations(result.error, "newsfeed");
      return;
    }
    await this.execute({
      requestFn: () => classroomio.course[":courseId"].newsfeed.$post({ param: { courseId }, json: result.data }),
      logContext: "creating newsfeed",
      onSuccess: (response) => {
        if (response.data) {
          snackbar.success("Post created successfully");
          const feedsArray = Array.isArray(this.feeds) ? this.feeds : [];
          const author = get(profile);
          const newFeed = {
            ...response.data,
            authorProfileId: author.id,
            authorFullname: author.fullname,
            authorUsername: author.username,
            authorAvatarUrl: author.avatarUrl,
            commentCount: 0
          };
          this.feeds = [...feedsArray, newFeed];
        }
      },
      onError: (result2) => {
        if (typeof result2 === "string") {
          snackbar.error("Failed to create post");
          return;
        }
        if ("error" in result2 && "field" in result2 && result2.field) {
          this.errors[result2.field] = result2.error;
          snackbar.error(result2.error);
        } else if ("error" in result2) {
          this.errors.general = result2.error;
          snackbar.error(result2.error);
        }
      }
    });
  }
  /**
   * Updates a newsfeed item (content and isPinned only)
   */
  async update(courseId, feedId, fields) {
    const result = ZNewsfeedUpdate.safeParse({ ...fields, content: getTextFromHTML(fields.content ?? "") });
    if (!result.success) {
      this.errors = mapZodErrorsToTranslations(result.error, "newsfeed");
      return;
    }
    await this.execute({
      requestFn: () => classroomio.course[":courseId"].newsfeed[":feedId"].$put({ param: { courseId, feedId }, json: result.data }),
      logContext: "updating newsfeed",
      onSuccess: (response) => {
        if (response.data) {
          snackbar.success("Post updated successfully");
          this.feeds = this.feeds.map((feed) => {
            if (feed.id !== feedId) {
              return feed;
            }
            return {
              ...feed,
              ...response.data,
              authorProfileId: feed.authorProfileId,
              authorFullname: feed.authorFullname,
              authorUsername: feed.authorUsername,
              authorAvatarUrl: feed.authorAvatarUrl
            };
          });
        }
      },
      onError: (result2) => {
        if (typeof result2 === "string") {
          snackbar.error("Failed to update post");
          return;
        }
        if ("error" in result2 && "field" in result2 && result2.field) {
          this.errors[result2.field] = result2.error;
          snackbar.error(result2.error);
        } else if ("error" in result2) {
          this.errors.general = result2.error;
          snackbar.error(result2.error);
        }
      }
    });
  }
  /**
   * Updates a newsfeed item's reaction
   */
  async react(courseId, feedId, reaction) {
    const result = ZNewsfeedReactionUpdate.safeParse({ reaction });
    if (!result.success) {
      this.errors = mapZodErrorsToTranslations(result.error, "newsfeed");
      return;
    }
    await this.execute({
      requestFn: () => classroomio.course[":courseId"].newsfeed[":feedId"].react.$put({ param: { courseId, feedId }, json: result.data }),
      logContext: "updating newsfeed reaction",
      onSuccess: (response) => {
        if (response.data) {
          this.feeds = this.feeds.map((feed) => {
            if (feed.id !== feedId) {
              return feed;
            }
            return {
              ...feed,
              ...response.data,
              authorProfileId: feed.authorProfileId,
              authorFullname: feed.authorFullname,
              authorUsername: feed.authorUsername,
              authorAvatarUrl: feed.authorAvatarUrl
            };
          });
        }
      },
      onError: (result2) => {
        if (typeof result2 === "string") {
          snackbar.error("Failed to update reaction");
          return;
        }
        if ("error" in result2 && "field" in result2 && result2.field) {
          this.errors[result2.field] = result2.error;
          snackbar.error(result2.error);
        } else if ("error" in result2) {
          this.errors.general = result2.error;
          snackbar.error(result2.error);
        }
      }
    });
  }
  /**
   * Deletes a newsfeed item
   */
  async delete(courseId, feedId) {
    await this.execute({
      requestFn: () => classroomio.course[":courseId"].newsfeed[":feedId"].$delete({ param: { courseId, feedId } }),
      logContext: "deleting newsfeed",
      onSuccess: (response) => {
        if (response.data) {
          snackbar.success("Post deleted successfully");
          this.feeds = this.feeds.filter((feed) => feed.id !== feedId);
        }
      },
      onError: (result) => {
        if (typeof result === "string") {
          snackbar.error("Failed to delete post");
        }
      }
    });
  }
  /**
   * Initialize comment state for a feed
   */
  initComments(feedId, totalCount) {
    if (!this.commentsByFeedId[feedId]) {
      this.commentsByFeedId[feedId] = {
        items: [],
        totalCount,
        hasMore: totalCount > 0,
        isLoading: false,
        cursor: null
      };
    } else {
      this.commentsByFeedId[feedId].totalCount = totalCount;
      this.commentsByFeedId[feedId].hasMore = totalCount > this.commentsByFeedId[feedId].items.length;
    }
  }
  /**
   * Fetch paginated comments for a feed
   */
  async getComments(courseId, feedId, limit = 5) {
    if (!this.commentsByFeedId[feedId]) {
      this.initComments(feedId, 0);
    }
    this.commentsByFeedId[feedId].isLoading = true;
    await this.execute({
      requestFn: () => classroomio.course[":courseId"].newsfeed[":feedId"].comments.$get({ param: { courseId, feedId }, query: { limit: String(limit) } }),
      logContext: "fetching newsfeed comments",
      onSuccess: (response) => {
        if (response.data) {
          this.commentsByFeedId[feedId] = {
            items: response.data.items,
            totalCount: response.data.totalCount,
            hasMore: response.data.hasMore,
            isLoading: false,
            cursor: response.data.nextCursor
          };
        }
      },
      onError: (result) => {
        this.commentsByFeedId[feedId].isLoading = false;
        if (typeof result === "string") {
          snackbar.error("Failed to fetch comments");
        }
      }
    });
  }
  /**
   * Load more comments (uses cursor)
   */
  async loadMoreComments(courseId, feedId, limit = 5) {
    const commentState = this.commentsByFeedId[feedId];
    if (!commentState || !commentState.hasMore || commentState.isLoading || !commentState.cursor) {
      return;
    }
    commentState.isLoading = true;
    await this.execute({
      requestFn: () => classroomio.course[":courseId"].newsfeed[":feedId"].comments.$get({
        param: { courseId, feedId },
        query: { cursor: commentState.cursor, limit: String(limit) }
      }),
      logContext: "loading more newsfeed comments",
      onSuccess: (response) => {
        if (response.data) {
          this.commentsByFeedId[feedId] = {
            items: [...commentState.items, ...response.data.items],
            totalCount: response.data.totalCount,
            hasMore: response.data.hasMore,
            isLoading: false,
            cursor: response.data.nextCursor
          };
        }
      },
      onError: (result) => {
        this.commentsByFeedId[feedId].isLoading = false;
        if (typeof result === "string") {
          snackbar.error("Failed to load more comments");
        }
      }
    });
  }
  /**
   * Creates a newsfeed comment
   */
  async createComment(courseId, feedId, content, author) {
    const result = ZNewsfeedCommentCreate.safeParse({ courseNewsfeedId: feedId, content });
    console.log("result", result);
    if (!result.success) {
      this.errors = mapZodErrorsToTranslations(result.error, "newsfeed");
      return;
    }
    await this.execute({
      requestFn: () => classroomio.course[":courseId"].newsfeed[":feedId"].comment.$post({ param: { courseId, feedId }, json: result.data }),
      logContext: "creating newsfeed comment",
      onSuccess: (response) => {
        if (response.data) {
          snackbar.success("Comment added successfully");
          const commentState = this.commentsByFeedId[feedId];
          if (commentState) {
            const newComment = {
              ...response.data,
              // Map author data to the expected flat structure
              authorProfileId: author.id,
              authorFullname: author.fullname,
              authorUsername: author.username,
              authorAvatarUrl: author.avatarUrl
            };
            this.commentsByFeedId[feedId] = {
              ...commentState,
              items: [newComment, ...commentState.items],
              totalCount: commentState.totalCount + 1
            };
          }
        }
      },
      onError: (result2) => {
        if (typeof result2 === "string") {
          snackbar.error("Failed to add comment");
        }
      }
    });
  }
  /**
   * Updates a newsfeed comment
   */
  async updateComment(courseId, commentId, content) {
    const result = ZNewsfeedCommentUpdate.safeParse({ content });
    if (!result.success) {
      this.errors = mapZodErrorsToTranslations(result.error, "newsfeed");
      return;
    }
    await this.execute({
      requestFn: () => classroomio.course[":courseId"].newsfeed.comment[":commentId"].$put({ param: { courseId, commentId }, json: result.data }),
      logContext: "updating newsfeed comment",
      onError: (result2) => {
        if (typeof result2 === "string") {
          snackbar.error("Failed to update comment");
        }
      }
    });
  }
  /**
   * Deletes a newsfeed comment
   */
  async deleteComment(courseId, feedId, commentId) {
    await this.execute({
      requestFn: () => classroomio.course[":courseId"].newsfeed.comment[":commentId"].$delete({ param: { courseId, commentId } }),
      logContext: "deleting newsfeed comment",
      onSuccess: (response) => {
        if (response.data) {
          snackbar.success("Comment deleted successfully");
          const commentState = this.commentsByFeedId[feedId];
          if (commentState) {
            this.commentsByFeedId[feedId] = {
              ...commentState,
              items: commentState.items.filter((item) => String(item.id) !== commentId),
              totalCount: Math.max(0, commentState.totalCount - 1)
            };
          }
        }
      },
      onError: (result) => {
        if (typeof result === "string") {
          snackbar.error("Failed to delete comment");
        }
      }
    });
  }
}
